use std::collections::HashMap;
use std::sync::{Arc, Mutex, RwLock};
use std::thread;

#[derive(Debug, Clone)]
pub struct Product {
    pub id: u64,
    pub name: String,
    pub stock: u64,
    pub price_cents: u64,
}

#[derive(Debug)]
pub struct InventoryManager {
    products: RwLock<HashMap<u64, Mutex<Product>>>,
}

#[derive(Debug, Clone, PartialEq)]
pub enum InventoryError {
    ProductNotFound(u64),
    InsufficientStock { product_id: u64, requested: u64, available: u64 },
    InvalidQuantity,
    LockPoisoned(String),
}

impl std::fmt::Display for InventoryError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            InventoryError::ProductNotFound(id) => write!(f, "Product with id {} not found", id),
            InventoryError::InsufficientStock { product_id, requested, available } => {
                write!(f, "Insufficient stock for product {}: requested {}, available {}", product_id, requested, available)
            }
            InventoryError::InvalidQuantity => write!(f, "Invalid quantity: must be greater than zero"),
            InventoryError::LockPoisoned(msg) => write!(f, "Lock poisoned: {}", msg),
        }
    }
}

impl std::error::Error for InventoryError {}

impl InventoryManager {
    pub fn new() -> Self {
        InventoryManager {
            products: RwLock::new(HashMap::new()),
        }
    }

    pub fn add_product(&self, product: Product) -> Result<(), InventoryError> {
        let mut products = self.products.write().map_err(|e| {
            InventoryError::LockPoisoned(format!("Failed to acquire write lock: {}", e))
        })?;
        products.insert(product.id, Mutex::new(product));
        Ok(())
    }

    pub fn check_stock(&self, product_id: u64) -> Result<u64, InventoryError> {
        let products = self.products.read().map_err(|e| {
            InventoryError::LockPoisoned(format!("Failed to acquire read lock: {}", e))
        })?;
        let product_mutex = products.get(&product_id)
            .ok_or(InventoryError::ProductNotFound(product_id))?;
        let product = product_mutex.lock().map_err(|e| {
            InventoryError::LockPoisoned(format!("Failed to lock product {}: {}", product_id, e))
        })?;
        Ok(product.stock)
    }

    pub fn decrement_stock(&self, product_id: u64, quantity: u64) -> Result<u64, InventoryError> {
        if quantity == 0 {
            return Err(InventoryError::InvalidQuantity);
        }

        let products = self.products.read().map_err(|e| {
            InventoryError::LockPoisoned(format!("Failed to acquire read lock: {}", e))
        })?;
        let product_mutex = products.get(&product_id)
            .ok_or(InventoryError::ProductNotFound(product_id))?;
        let mut product = product_mutex.lock().map_err(|e| {
            InventoryError::LockPoisoned(format!("Failed to lock product {}: {}", product_id, e))
        })?;

        if product.stock < quantity {
            return Err(InventoryError::InsufficientStock {
                product_id,
                requested: quantity,
                available: product.stock,
            });
        }

        product.stock -= quantity;
        Ok(product.stock)
    }

    pub fn restock(&self, product_id: u64, quantity: u64) -> Result<u64, InventoryError> {
        if quantity == 0 {
            return Err(InventoryError::InvalidQuantity);
        }

        let products = self.products.read().map_err(|e| {
            InventoryError::LockPoisoned(format!("Failed to acquire read lock: {}", e))
        })?;
        let product_mutex = products.get(&product_id)
            .ok_or(InventoryError::ProductNotFound(product_id))?;
        let mut product = product_mutex.lock().map_err(|e| {
            InventoryError::LockPoisoned(format!("Failed to lock product {}: {}", product_id, e))
        })?;

        product.stock = product.stock.checked_add(quantity)
            .ok_or(InventoryError::InvalidQuantity)?;
        Ok(product.stock)
    }

    pub fn get_product_info(&self, product_id: u64) -> Result<Product, InventoryError> {
        let products = self.products.read().map_err(|e| {
            InventoryError::LockPoisoned(format!("Failed to acquire read lock: {}", e))
        })?;
        let product_mutex = products.get(&product_id)
            .ok_or(InventoryError::ProductNotFound(product_id))?;
        let product = product_mutex.lock().map_err(|e| {
            InventoryError::LockPoisoned(format!("Failed to lock product {}: {}", product_id, e))
        })?;
        Ok(product.clone())
    }
}

pub fn process_concurrent_orders(
    inventory: Arc<InventoryManager>,
    orders: Vec<(u64, u64)>, // Vec of (product_id, quantity)
    num_threads: usize,
) -> Vec<Result<u64, InventoryError>> {
    let orders = Arc::new(orders);
    let results: Arc<Mutex<Vec<(usize, Result<u64, InventoryError>)>>> =
        Arc::new(Mutex::new(Vec::new()));

    let total_orders = orders.len();
    let chunk_size = (total_orders + num_threads - 1) / num_threads;

    let mut handles = Vec::new();

    for thread_idx in 0..num_threads {
        let inventory = Arc::clone(&inventory);
        let orders = Arc::clone(&orders);
        let results = Arc::clone(&results);

        let start = thread_idx * chunk_size;
        let end = std::cmp::min(start + chunk_size, total_orders);

        if start >= total_orders {
            break;
        }

        let handle = thread::spawn(move || {
            for i in start..end {
                let (product_id, quantity) = orders[i];
                let result = inventory.decrement_stock(product_id, quantity);
                let mut results_guard = results.lock().expect("Results lock poisoned");
                results_guard.push((i, result));
            }
        });

        handles.push(handle);
    }

    for handle in handles {
        handle.join().expect("Thread panicked");
    }

    let mut indexed_results = Arc::try_unwrap(results)
        .expect("Arc still has multiple owners")
        .into_inner()
        .expect("Mutex poisoned");

    indexed_results.sort_by_key(|(idx, _)| *idx);
    indexed_results.into_iter().map(|(_, result)| result).collect()
}

fn main() {
    let inventory = Arc::new(InventoryManager::new());

    // Add some products
    inventory.add_product(Product {
        id: 1,
        name: "Laptop".to_string(),
        stock: 100,
        price_cents: 99999,
    }).unwrap();

    inventory.add_product(Product {
        id: 2,
        name: "Mouse".to_string(),
        stock: 500,
        price_cents: 2999,
    }).unwrap();

    inventory.add_product(Product {
        id: 3,
        name: "Keyboard".to_string(),
        stock: 200,
        price_cents: 7999,
    }).unwrap();

    // Simulate concurrent orders
    let mut orders = Vec::new();
    for _ in 0..50 {
        orders.push((1, 1)); // Buy 1 laptop
        orders.push((2, 3)); // Buy 3 mice
        orders.push((3, 2)); // Buy 2 keyboards
    }

    println!("Initial stock levels:");
    println!("  Laptop: {}", inventory.check_stock(1).unwrap());
    println!("  Mouse: {}", inventory.check_stock(2).unwrap());
    println!("  Keyboard: {}", inventory.check_stock(3).unwrap());

    let results = process_concurrent_orders(Arc::clone(&inventory), orders, 8);

    let successful = results.iter().filter(|r| r.is_ok()).count();
    let failed = results.iter().filter(|r| r.is_err()).count();

    println!("\nProcessed {} orders: {} successful, {} failed", results.len(), successful, failed);

    println!("\nFinal stock levels:");
    println!("  Laptop: {}", inventory.check_stock(1).unwrap());
    println!("  Mouse: {}", inventory.check_stock(2).unwrap());
    println!("  Keyboard: {}", inventory.check_stock(3).unwrap());

    // Demonstrate error handling
    match inventory.decrement_stock(999, 1) {
        Err(InventoryError::ProductNotFound(id)) => {
            println!("\nExpected error: Product {} not found", id);
        }
        _ => panic!("Expected ProductNotFound error"),
    }

    match inventory.decrement_stock(1, 0) {
        Err(InventoryError::InvalidQuantity) => {
            println!("Expected error: Invalid quantity");
        }
        _ => panic!("Expected InvalidQuantity error"),
    }
}

